import React, { useState } from 'react';

const AdminPanel = ({ rooms, archive, dailyLogs, threshold, setThreshold, users, setUsers }) => {
    const [view, setView] = useState('stats'); // stats, archive, products, users
    const [newUser, setNewUser] = useState({ login: '', pass: '', role: 'staff' });

    // --- ФУНКЦИИ ПЕРСОНАЛА ---
    const handleAddUser = () => {
        if (!newUser.login || !newUser.pass) return alert("Заполните логин и пароль");
        if (users.find(u => u.login === newUser.login)) return alert("Логин занят");
        setUsers([...users, newUser]);
        setNewUser({ login: '', pass: '', role: 'staff' });
        alert("Пользователь добавлен!");
    };

    const handleChangePassword = (login) => {
        const newPass = prompt(`Новый пароль для ${login}:`);
        if (newPass) {
            setUsers(users.map(u => u.login === login ? { ...u, pass: newPass } : u));
        }
    };

    const handleDeleteUser = (login) => {
        if (login === 'admin') return alert("Нельзя удалить админа");
        if (window.confirm(`Удалить ${login}?`)) {
            setUsers(users.filter(u => u.login !== login));
        }
    };

    // --- СТАТИСТИКА ТОВАРОВ ---
    const getProductStats = () => {
        let stats = {};
        rooms.forEach(room => {
            room.inventory.forEach(item => {
                if (!stats[item.name]) stats[item.name] = { total: 0, expired: 0 };
                stats[item.name].total += item.count;
                if (item.expiry && item.expiry !== 'нет' && item.expiry !== '') {
                    const diff = (new Date(item.expiry) - new Date()) / (1000 * 60 * 60 * 24);
                    if (diff < threshold) stats[item.name].expired += 1;
                }
            });
        });
        return stats;
    };
    const productStats = getProductStats();

    return (
        <div className="page-content fade-in">
            <h2 className="page-title">Management</h2>

            {/* Навигация */}
            <div className="threshold-buttons" style={{ marginBottom: '20px', display: 'flex', overflowX: 'auto' }}>
                <button className={`t-btn ${view === 'stats' ? 'active' : ''}`} onClick={() => setView('stats')}>LIVE</button>
                <button className={`t-btn ${view === 'archive' ? 'active' : ''}`} onClick={() => setView('archive')}>АРХИВ</button>
                <button className={`t-btn ${view === 'products' ? 'active' : ''}`} onClick={() => setView('products')}>ТОВАРЫ</button>
                <button className={`t-btn ${view === 'users' ? 'active' : ''}`} onClick={() => setView('users')}>ПЕРСОНАЛ</button>
            </div>

            {/* ВКЛАДКА: LIVE */}
            {view === 'stats' && (
                <div className="fade-in">
                    <div className="admin-stats-grid">
                        <div className="stat-card">
                            <span className="stat-value">{rooms.filter(r => r.status === 'checked').length}</span>
                            <span className="stat-label">Проверено</span>
                        </div>
                        <div className="stat-card">
                            <span className="stat-value">{rooms.filter(r => r.status === 'dnd').length}</span>
                            <span className="stat-label">DND</span>
                        </div>
                    </div>
                    <div className="admin-settings-section">
                        <h3>Лента за сегодня</h3>
                        {dailyLogs.map((log, i) => (
                            <div key={i} style={{fontSize: '12px', padding: '5px 0', borderBottom: '1px solid #eee'}}>
                                <b>{log.time}</b> | {log.staff} | №{log.roomId} ({log.action})
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* ВКЛАДКА: ПЕРСОНАЛ */}
            {view === 'users' && (
                <div className="fade-in">
                    <div className="admin-settings-section" style={{background: '#fcf8f0'}}>
                        <h3>+ Новый аккаунт</h3>
                        <input className="search-input" placeholder="Логин" value={newUser.login} onChange={e => setNewUser({...newUser, login: e.target.value})} style={{marginBottom: '10px'}}/>
                        <input className="search-input" placeholder="Пароль" value={newUser.pass} onChange={e => setNewUser({...newUser, pass: e.target.value})} style={{marginBottom: '10px'}}/>
                        <button className="btn-download" onClick={handleAddUser}>ДОБАВИТЬ</button>
                    </div>
                    <div className="admin-settings-section">
                        <h3>Список сотрудников</h3>
                        {users.map((u, i) => (
                            <div key={i} style={{display: 'flex', justifyContent: 'space-between', padding: '10px 0', borderBottom: '1px solid #eee'}}>
                                <div><b>{u.login}</b> <br/><small>Пароль: {u.pass}</small></div>
                                <div>
                                    <button onClick={() => handleChangePassword(u.login)} style={{marginRight: '10px', background: 'none', border: '1px solid #ccc', borderRadius: '4px'}}>🔑</button>
                                    {u.login !== 'admin' && <button onClick={() => handleDeleteUser(u.login)} style={{color: 'red', background: 'none', border: 'none'}}>❌</button>}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* ВКЛАДКА: ТОВАРЫ */}
            {view === 'products' && (
                <div className="admin-settings-section fade-in">
                    <h3>Статистика запасов</h3>
                    {Object.keys(productStats).map(name => (
                        <div key={name} style={{display: 'flex', justifyContent: 'space-between', padding: '8px 0', borderBottom: '1px solid #f9f9f9'}}>
                            <span>{name}</span>
                            <span>{productStats[name].total} шт. (Срок: <b style={{color: 'red'}}>{productStats[name].expired}</b>)</span>
                        </div>
                    ))}
                </div>
            )}

            {/* ВКЛАДКА: АРХИВ */}
            {view === 'archive' && (
                <div className="admin-settings-section fade-in">
                    <h3>Архив (00:00)</h3>
                    {archive.map((day, i) => (
                        <div key={i} style={{padding: '10px', background: '#f8f9fa', marginBottom: '5px'}}>
                            <b>{day.date}</b>: {day.stats.checked} ОК / {day.stats.dnd} DND
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default AdminPanel;
